package com.projectbible.post.gradle.jpa.mysql.board.presentation;
import com.projectbible.post.gradle.jpa.mysql.board.application.BoardQueryService; import com.projectbible.post.gradle.jpa.mysql.common.api.ApiResponse; import io.swagger.v3.oas.annotations.Operation; import io.swagger.v3.oas.annotations.tags.Tag; import java.util.List; import java.util.Map; import org.springframework.web.bind.annotation.*;
@Tag(name="boards") @RestController @RequestMapping("/api/v1/boards") public class BoardController { private final BoardQueryService service; public BoardController(BoardQueryService service) { this.service=service; } @Operation(summary="List boards") @GetMapping public ApiResponse<List<Map<String,Object>>> list() { List<Map<String,Object>> items=service.list(); return ApiResponse.success(items,Map.of("page",1,"limit",items.size(),"totalCount",items.size(),"totalPages",1)); } }
